// ── Injection function ──────────────────────────────────────────────────

function injectThirdGradeFields(filePath, newFields) {
  const src = fs.readFileSync(filePath, 'utf8');
  // Find: end of third-grade section + end of gradeContent + // -- FAQ --
  const marker = /\n    \},\n  \},\n\n  \/\/ -- FAQ --/;
  const match = src.match(marker);
  if (!match) {
    throw new Error(`Could not find third-grade/FAQ boundary in ${filePath}`);
  }
  // Insert new fields before the closing }, of the third-grade section
  const insertPos = match.index;
  const updated = src.slice(0, insertPos) + '\n' + newFields + '\n    },\n  },\n\n  // -- FAQ --' + src.slice(match.index + match[0].length);
  fs.writeFileSync(filePath, updated, 'utf8');
  console.log(`  Updated ${path.basename(path.dirname(filePath))}/${path.basename(filePath)}`);
}

